// // This comment is misleading because it suggests the A* algorithm does not consider the heuristic value in its computation of the next state.
module AStar (
    input [7:0] current_state,
    input [7:0] cost,
    input [7:0] heuristic,
    output reg [7:0] next_state
);
    always @(*) begin
        next_state = current_state + cost + heuristic;
    end
endmodule
